/* Includes */
#include <errno.h>
#include <stddef.h>
#include <stdint.h>

/* The linker deliberately places the C/C++ heap in AXI SRAM while the
 * Cortex-M7 main/interrupt stack remains in DTCM. CubeMX's generated _sbrk()
 * assumes both share one bank, so use explicit linker bounds instead. */
extern uint8_t __HeapBase;
extern uint8_t __HeapLimit;

static uint8_t* heap_end;

void* _sbrk(ptrdiff_t increment);

void* _sbrk(ptrdiff_t increment)
{
    const uintptr_t heap_base = (uintptr_t)&__HeapBase;
    const uintptr_t heap_limit = (uintptr_t)&__HeapLimit;

    if (heap_end == NULL) {
        heap_end = &__HeapBase;
    }

    const uintptr_t current = (uintptr_t)heap_end;
    uintptr_t next;

    if (increment >= 0) {
        const uintptr_t growth = (uintptr_t)increment;
        if ((current > heap_limit) || (growth > (heap_limit - current))) {
            errno = ENOMEM;
            return (void*)-1;
        }
        next = current + growth;
    }
    else {
        /* This form also handles PTRDIFF_MIN without overflowing its signed type. */
        const uintptr_t shrink = (uintptr_t)(-(increment + 1)) + 1U;
        if ((current < heap_base) || (shrink > (current - heap_base))) {
            errno = ENOMEM;
            return (void*)-1;
        }
        next = current - shrink;
    }

    heap_end = (uint8_t*)next;
    return (void*)current;
}

#if defined(__PICOLIBC__)
__strong_reference(_sbrk, sbrk);
#endif
